45	func addProtocolFlag(cmd *cobra.Command, mode *protocolModeFlag) {
46		cmd.Flags().Var(mode, "protocol", "protocol mode: auto, v1, or v2")
47	}
48	
49	func newProtocolFlag() protocolModeFlag {
50		return protocolModeFlag(protocolMode(envOr("GITSYNC_PROTOCOL", validation.ProtocolAuto)))
51	}
52	
53	func envOr(key, fallback string) string {
54		value := os.Getenv(key)
55		if value == "" {
56			return fallback
57		}
58		return value
59	}
60	
61	func envBool(key string) bool {
62		value := strings.TrimSpace(strings.ToLower(os.Getenv(key)))
63		return value == "1" || value == "true" || value == "yes" || value == "on"
64	}
65	
66	func splitCSV(value string) []string {
67		parts := strings.Split(value, ",")
68		out := make([]string, 0, len(parts))
69		for _, part := range parts {
70			part = strings.TrimSpace(part)
71			if part != "" {
72				out = append(out, part)
73			}
74		}
75		return out
76	}
