78	type protocolMode gitsync.ProtocolMode
79	type operationMode gitsync.OperationMode
80	
81	type protocolModeFlag protocolMode
82	type operationModeFlag operationMode
83	
84	func (p *protocolModeFlag) String() string { return string(*p) }
85	func (p *protocolModeFlag) Type() string   { return "string" }
86	
87	func (p *protocolModeFlag) Set(value string) error {
88		mode, err := validation.NormalizeProtocolMode(value)
89		if err != nil {
90			return fmt.Errorf("normalize protocol: %w", err)
91		}
92		*p = protocolModeFlag(protocolMode(gitsync.ProtocolMode(mode)))
93		return nil
94	}
95	
96	func (m *operationModeFlag) String() string { return string(*m) }
97	func (m *operationModeFlag) Type() string   { return "string" }
98	
99	func (m *operationModeFlag) Set(value string) error {
100		switch gitsync.OperationMode(value) {
101		case gitsync.ModeSync, gitsync.ModeReplicate:
102			*m = operationModeFlag(operationMode(value))
103			return nil
104		default:
105			return fmt.Errorf("unsupported mode %q", value)
106		}
107	}
108	
109	// defaultOperationMode returns the starting value for the --mode flag.
110	// Subcommands that pin a mode (sync, replicate) pass it in; plan passes ""
111	// and gets sync as the default, letting --mode override it.
112	func defaultOperationMode(defaultMode gitsync.OperationMode) operationMode {
113		if defaultMode != "" {
114			return operationMode(defaultMode)
115		}
116		return operationMode(gitsync.ModeSync)
117	}
