func (s *statsCollector) liveSides() []SideBytes {
	s.sidesMu.RLock()
	defer s.sidesMu.RUnlock()
	out := make([]SideBytes, 0, len(s.sides))
	for label, sc := range s.sides {
		out = append(out, SideBytes{
			Label:   label,
			Bytes:   sc.bytes.Load(),
			Display: sc.display,
