func (p *progressReporter) notify(msg string) {
	p.mu.Lock()
	defer p.mu.Unlock()
	if p.lastLen > 0 {
		fmt.Fprint(p.out, "\r"+strings.Repeat(" ", p.lastLen)+"\r")
	}
